        $messages = array(
            array('id' => '5','source_url' => env('APP_URL').'/message/5/actsafe-performing-arts-safety-for-supervisors-course','subject' => 'ActSafe Performing Arts Safety for Supervisors Course','slug' => 'actsafe-performing-arts-safety-for-supervisors-course','content' => '<div style="text-align:left;"><p><span style="font-size:16px;">Dear Brothers, Sisters, and Kin,</span><br><br><span style="font-size:16px;">ActSafe is holding their Performing Arts Safety for Supervisors Course on Sept 24th. The course is free to attend and you can </span><a style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;color:#007C89;font-weight:normal;mso-line-height-rule:exactly;" target="_blank" rel="noopener noreferrer" href="https://www.actsafestar.ca/v1/index.cfm?action=classroom.eventdetails&amp;event=_38F38F33E3C585A9EE52E9DFF8EE3C81&amp;company=_F85D73A3726426776D40A735F9B097DC"><span style="color:#0000FF;font-size:16px;"><u>register here</u></span></a></p><h2 style="color:#202020;display:block;font-family:Helvetica;font-size:22px;font-style:normal;letter-spacing:normal;line-height:125%;margin:0;padding:0;text-align:left;"><strong>Course Overview</strong></h2><p style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;color:#202020;font-family:Helvetica;font-size:16px;line-height:150%;margin:10px 0;mso-line-height-rule:exactly;padding:0;text-align:left;"><span class="pSize"><strong>Workshop Delivery:</strong> Virtual</span><br><span class="pSize"><strong>Workshop Cost:</strong> FREE</span><br><span class="pSize"><strong>Workshop Duration:</strong> 5hrs</span></p><p style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;color:#202020;font-family:Helvetica;font-size:16px;line-height:150%;margin:10px 0;mso-line-height-rule:exactly;padding:0;text-align:left;"><span class="pSize">This four-hour highly interactive general safety workshop is designed specifically for&nbsp;<strong>PERFORMING ARTS, THEATRE and LIVE EVENTS WORKERS and meets the requirements of IATSE 118</strong>.</span></p><p style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;color:#202020;font-family:Helvetica;font-size:16px;line-height:150%;margin:10px 0;mso-line-height-rule:exactly;padding:0;text-align:left;"><span class="pSize">Topics covered include, but are not limited to:&nbsp;</span></p><ul><li style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;mso-line-height-rule:exactly;"><span class="pSize">identifying hazards,</span></li><li style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;mso-line-height-rule:exactly;"><span class="pSize">rights and responsibilities and</span></li><li style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;mso-line-height-rule:exactly;"><span class="pSize">the importance of safety committees in the workplace.</span></li></ul><p style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;color:#202020;font-family:Helvetica;font-size:16px;line-height:150%;margin:10px 0;mso-line-height-rule:exactly;padding:0;text-align:left;"><span class="pSize">This workshop&nbsp;<strong>DOES NOT</strong> meet the union requirements for application to IATSE Local 891.</span></p><p style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;color:#202020;font-family:Helvetica;font-size:16px;line-height:150%;margin:10px 0;mso-line-height-rule:exactly;padding:0;text-align:left;"><span class="pSize">Please refer to the <strong>MOTION PICTURE Safety Awareness course</strong> for those requirements.</span></p></div>','user_id' => '1','count' => '1','state' => 'sent','created_at' => '2024-12-06 04:38:27','updated_at' => '2024-12-06 05:20:24'),
            array('id' => '6','source_url' => env('APP_URL').'/message/6/2024-pin-party-rsvp-by-oct-5th','subject' => '2024 Pin Party - RSVP by Oct 5th','slug' => '2024-pin-party-rsvp-by-oct-5th','content' => '<p>Dear Brothers, Sisters, and Kin,<br><br>The Annual 118 Pin Party to give out years of service pins will be held on October 14th 2024.<br><strong>Please RSVP by October 5th to Heather Turnbull at: </strong><a style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;color:#007C89;font-weight:normal;mso-line-height-rule:exactly;" target="_blank" rel="noopener noreferrer" href="http://htfarmgirl@live.com"><span style="color:#0000FF;"><strong><u>htfarmgirl@live.com</u></strong></span></a></p><p>&nbsp;</p>','user_id' => '1','count' => '1','state' => 'sent','created_at' => '2024-12-06 04:41:00','updated_at' => '2024-12-06 05:20:43'),
            array('id' => '7','source_url' => env('APP_URL').'/message/7/city-of-vancouver-contract-ratification-results','subject' => 'City of Vancouver Contract Ratification Results','slug' => 'city-of-vancouver-contract-ratification-results','content' => '<div style="text-align:left;"><p><span style="font-family:helvetica neue,helvetica,arial,verdana,sans-serif;">Dear Sisters, Brothers, and Kin,</span><br>&nbsp;</p><div><span style="font-family:helvetica neue,helvetica,arial,verdana,sans-serif;">The City of Vancouver Memorandum of Agreement has been ratified by the Bargaining Unit. With 90 votes cast:</span><br><br><span style="font-family:helvetica neue,helvetica,arial,verdana,sans-serif;">85 votes in Favour</span><br><span style="font-family:helvetica neue,helvetica,arial,verdana,sans-serif;">3 votes Opposed</span><br><span style="font-family:helvetica neue,helvetica,arial,verdana,sans-serif;">2 voters Abstained</span><br><br><span style="font-family:helvetica neue,helvetica,arial,verdana,sans-serif;">Thank you to everyone who participated.</span><br><span style="font-family:helvetica neue,helvetica,arial,verdana,sans-serif;">More Information regarding the voting process can be found here: </span><a style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;color:#007C89;font-weight:normal;mso-line-height-rule:exactly;" target="_blank" rel="noopener noreferrer" href="https://iatse118.com/post/2024-city-of-vancouver-vct-2023-2026-contract-renewal"><span style="color:#0000FF;font-family:helvetica neue,helvetica,arial,verdana,sans-serif;"><u>https://iatse118.com/post/2024-city-of-vancouver-vct-2023-2026-contract-renewal</u></span></a></div><div><span style="font-family:helvetica neue,helvetica,arial,verdana,sans-serif;">&nbsp;</span><br><span style="font-family:helvetica neue,helvetica,arial,verdana,sans-serif;">The City of Vancouver has similarly ratified the agreement. Additionally, </span><span style="-moz-text-size-adjust:auto;-webkit-text-stroke-width:0px;caret-color:#000000;color:#000000;display:inline !important;float:none;font-family:helvetica neue,helvetica,arial,verdana,sans-serif;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;text-align:start;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;word-spacing:0px;">Retro pay for all work done under the Vancouver Civic Theatres agreement for 2023 and 2024 will be paid out on the October 25 payroll. Additionally, a 1% lump sum recognition payment of all straight time wages earned in 2023 up to and including November 16</span><span style="font-family:helvetica neue,helvetica,arial,verdana,sans-serif;"><sup style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;caret-color:#000000;color:#000000;font-family:Calibri, sans-serif;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;orphans:auto;text-align:start;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">th</sup></span><span style="-moz-text-size-adjust:auto;-webkit-text-stroke-width:0px;caret-color:#000000;color:#000000;display:inline !important;float:none;font-family:helvetica neue,helvetica,arial,verdana,sans-serif;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;text-align:start;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;word-spacing:0px;">&nbsp;will be paid out on the November 8th payroll, and a 3.5% lump sum of all straight time wages earned in 2022 will be paid out on the November 22nd payroll.&nbsp;</span></div></div>','user_id' => '1','count' => '1','state' => 'sent','created_at' => '2024-12-06 04:41:43','updated_at' => '2024-12-06 05:20:44'),
            array('id' => '9','source_url' => env('APP_URL').'/message/9/taylor-swift-show-bc-place','subject' => 'Taylor Swift Show - BC Place','slug' => 'taylor-swift-show-bc-place','content' => '<div class="elementToProof" style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">Hello Local 118 Members.</div><div style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">&nbsp;</div><div class="elementToProof" style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">Just wanting to announce some good news that will provide the Local with work and income during what is normally a slow Holiday Season.&nbsp;</div><div style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">&nbsp;</div><div style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">Local 118 has secured the Taylor Swift show at BC Place for Dec 6,7,8th !&nbsp;</div><div style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">&nbsp;</div><div class="elementToProof" style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">Due to the sheer size and logistics of this show,&nbsp; AEG has finally realised that our excellent track record with Dome shows speaks for itself and we are the only ones in town that can make show of this scale happen with reliability safety and efficiency.&nbsp;</div><div style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">&nbsp;</div><div class="elementToProof" style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">Securing this show is a HUGE opportunity for 118. An opportunity that could not have happened without our Business Agent Joe Sawan.&nbsp; He has spearheaded and led the team from the start and deserves many thanks and much credit. Thank you, Joe.&nbsp;</div><div style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">&nbsp;</div><div class="elementToProof" style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">Members of 118 should all be proud of our top-tier work ethic and reputation which has earned us this great opportunity and more future dealings with AEG.&nbsp; &nbsp;</div><div style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;"><br>More details/dates regarding steel and production dates will be sent out as they become finalized.</div><div style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">&nbsp;</div><div style="-webkit-text-size-adjust:auto;-webkit-text-stroke-width:0px;color:#000000;font-family:Aptos, Aptos_EmbeddedFont, Aptos_MSFontService, Calibri, Helvetica, sans-serif;font-size:12pt;font-style:normal;font-variant-caps:normal;font-weight:400;letter-spacing:normal;margin:0px;orphans:auto;text-align:left;text-decoration:none;text-indent:0px;text-transform:none;white-space:normal;widows:auto;word-spacing:0px;">So that\'s good news!!</div>','user_id' => '1','count' => '0','state' => 'sent','created_at' => '2024-12-06 04:44:06','updated_at' => '2024-12-06 05:20:44'),
            array('id' => '10','source_url' => env('APP_URL').'/message/10/job-posting-vancouver-civic-theatres','subject' => 'JOB POSTING Vancouver Civic Theatres','slug' => 'job-posting-vancouver-civic-theatres','content' => '<p>Dear 118 Members,<br><br>Vancouver Civic Theatres is hiring a Head Resident Stage Electrician (Console Op) for the Queen Elizabeth Theatre, the job posting can be found here: https://iatse118.com/job/154<br>The posting will remain open until filled.&nbsp;</p>','user_id' => '1','count' => '0','state' => 'sent','created_at' => '2024-12-06 04:46:32','updated_at' => '2024-12-06 05:20:45'),
            array('id' => '11','source_url' => env('APP_URL').'/message/11/last-chance-to-join-us-for-the-2024-years-of-service-awards-party','subject' => 'LAST CHANCE to join us for the 2024 Years of Service Awards Party!','slug' => 'last-chance-to-join-us-for-the-2024-years-of-service-awards-party','content' => '<p>Dear Brothers, Sisters, and Kin,<br><br>There are 43 spots still available for tomorrow nights Pin Party!&nbsp; Please RSVP ASAP to Heather at <a style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;color:#007C89;font-weight:normal;mso-line-height-rule:exactly;" href="mailto:htfarmgirl@live.com" target="_blank"><span style="color:#0000FF;"><u>htfarmgirl@live.com</u></span></a> if you would like to attend.&nbsp;<br><br>It\'s not too late! Gonna be a great night, and we would love to see everyone there.<br><br>All 118 Members are welcome, you do not have to be receiving a pin in order to attend.</p>','user_id' => '1','count' => '1','state' => 'sent','created_at' => '2024-12-06 04:47:25','updated_at' => '2024-12-06 05:20:46'),
            array('id' => '12','source_url' => env('APP_URL').'/message/12/118-health-plan-new-benefits','subject' => '118 Health Plan - New Benefits','slug' => '118-health-plan-new-benefits','content' => '<div style="text-align:center;">The IATSE Local 118 Health and Welfare Plan is pleased to announce,<br><strong>COVERAGE FOR EYE EXAMS AND HEARING TESTS</strong><br><span style="background-color:#FFFF00;"><strong>at no additional cost to members</strong></span></div><div style="text-align:left;">&nbsp;<br>&nbsp;These new benefits will be available starting November 1, 2024 for;<br><br>&nbsp;1) <strong>all active members</strong> who have been either A members or B members for at least three months, and<br><br>&nbsp;2) <strong>all retired members</strong><br><br><i>This benefit does not include dependents</i>.<br><br>Details:<br><br><strong>Coverage for eye exams up to $125 in a twenty-four-month period.</strong><br><br><strong>Coverage for hearing tests up to $125 in a 60-month (5 year) period.&nbsp;</strong><br><br>In order to facilitate the mass enrollment of all eligible members, we will be providing Pacific Blue Cross with the following member information:<br><br>First and Last Names<br>Mailing Address<br>E-mail address<br>Date of Birth<br><br>If you have any concerns or <strong>DO NOT</strong> wish to participate in this benefit, please let the Administrator know by replying to this email before <strong>10 pm, Sunday, October 20<sup>th</sup></strong>.<br>&nbsp;<br>More information and details on claim procedure will be avaliable at a later date.</div>','user_id' => '1','count' => '1','state' => 'sent','created_at' => '2024-12-06 04:48:15','updated_at' => '2024-12-06 05:20:47'),
            array('id' => '13','source_url' => env('APP_URL').'/message/13/notice-of-general-meeting-sundayoctober-27th700-pm','subject' => 'NOTICE OF GENERAL MEETING Sunday:October 27th:7:00 PM','slug' => 'notice-of-general-meeting-sundayoctober-27th700-pm','content' => '<figure class="table"><table class="mcnBoxedTextBlock" style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;border-collapse:collapse;min-width:100%;mso-table-lspace:0pt;mso-table-rspace:0pt;" border="0" cellpadding="0" cellspacing="0" width="100%"><tbody class="mcnBoxedTextBlockOuter"><tr><td class="mcnBoxedTextBlockInner" style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;mso-line-height-rule:exactly;vertical-align:top;"><figure class="table" style="float:left;"><table class="mcnBoxedTextContentContainer" style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;border-collapse:collapse;min-width:100%;mso-table-lspace:0pt;mso-table-rspace:0pt;" border="0" cellpadding="0" cellspacing="0" width="100%"><tbody><tr><td style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;mso-line-height-rule:exactly;padding:9px 18px;"><figure class="table"><table class="mcnTextContentContainer" style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;background-color:#404040;border-collapse:collapse;min-width:100% !important;mso-table-lspace:0pt;mso-table-rspace:0pt;" border="0" cellspacing="0" width="100%"><tbody><tr><td class="mcnTextContent" style="-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%;color:#F2F2F2;font-family:Helvetica;font-size:14px;font-weight:normal;line-height:150%;mso-line-height-rule:exactly;padding:18px;text-align:center;vertical-align:top;word-break:break-word;"><div style="text-align:center;"><span style="font-size:16px;">The Next General Meeting of IATSE&nbsp;Local 118 will be held digitally Via a Zoom Webinar on</span><br><span style="font-size:20px;"><strong>Sunday, October 27th @ 7:00 PM</strong></span></div></td></tr></tbody></table></figure></td></tr></tbody></table></figure></td></tr></tbody></table></figure><p>&nbsp;<br>The Next General Meeting of IATSE Local 118 will be held digitally Via a Zoom Webinar on<br>Sunday, October 27th @ 7:00 PM<br>Dear Brothers, Sisters, and Kin:<br><br>To ensure security, members must register in advance. You will be sent a confirmation email with the details on how to join the meeting no less than 24 hours prior to the Call to Order.&nbsp;<br>&nbsp;</p><p>General Meeting Agenda</p><p>On the agenda for this meeting:</p><p>&nbsp; &nbsp;Approval of minutes from the previous General Meeting. &nbsp;<br>&nbsp; &nbsp;Reports, as outlined in the Constitution and By-Laws<br>&nbsp; &nbsp;Report from the Delegates to the 2024 IATSE Canadian Convention<br>&nbsp; &nbsp;Motion Regarding 2025 Officer Compensation<br>&nbsp; &nbsp;Draft Audit for the 2023 Year for the Payroll Trust Account<br>&nbsp; &nbsp;New Business</p><p>Any members or committees with business for the agenda must submit them to office@iatse118.com 48 hours in advance of the General Meeting.</p><p>IATSE Local 856 - Operation Warm<br>&nbsp;</p><p>At the most recent IATSE Canadian Convention, IATSE International encouraged all locals to participate in Operation Warm. This year IATSE Local 856 (Manitoba) is fundraising for Operation Warm and any donations are greatly appreciated. See communication below from IATSE 856.</p><p>Before the winter comes, We\'d like to ask for your help in raising money for a project called Operation Warm. This nonprofit organization helps children that are less fortunate get brand new coats and shoes.</p><p>Because schools are currently closed until September, we will be deciding on a school as soon as they are open. Hopefully we can choose more than one school and help as many children as possible.</p><p>Please feel free to share the link with family and friends as well as the QR code. It would also be a great help if you could share this with your current production.</p><p>https://secure.givelively.org/donate/operation-warm-inc/team-up-with-iatse-local-856</p><p>&nbsp;</p><p>Guidelines for attending a Zoom meeting:</p><p>&nbsp; &nbsp;Zoom can be run in your browser, but it will be easier if you download the app here: https://zoom.us/download.<br>&nbsp; &nbsp;In accordance with a directive from the International, attendees of all remote local 118 meetings will be required to keep their cameras on at all times except during break periods. Should an attendee be out of frame or have their camera turned off for a sustained time they will be removed from the meeting until they can reappear on camera.<br>&nbsp; &nbsp;Members will be able to “raise their hand” to ask questions and will be recognized by the Chair prior to having their microphone unmuted.<br>&nbsp; &nbsp;Members will also be able to type in their questions in the chat box.<br>&nbsp; &nbsp;The chat will be monitored by a member of the Executive. Points of Order and Points of Privilege can be submitted via the chat function and will be immediately addressed by the Chair.<br>&nbsp; &nbsp;Voting on motions will take place using the “poll” function.<br>&nbsp; &nbsp;Remember: General Meetings are confidential union business. Make sure that you are in a location where you cannot be overheard by non-members.<br>&nbsp; &nbsp;If you have any questions, please do not hesitate to contact the Executive Board ​at office@iatse118.com<br>&nbsp;</p>','user_id' => '1','count' => '1','state' => 'sent','created_at' => '2024-12-06 04:49:37','updated_at' => '2024-12-06 05:20:47'),
